{"code":"import json

# Load citations
with open(locals()['var_function-call-15646429060027290344'], 'r') as f:
    citations = json.load(f)

filenames = [c['title'] + ".txt" for c in citations]

queries = []
# Chunks 2, 3, 4
for i in range(1, 4):
    chunk_filenames = filenames[i*50 : (i+1)*50]
    if not chunk_filenames:
        continue
    query = {
        "collection": "paper_docs",
        "filter": {
            "filename": {"$in": chunk_filenames}
        }
    }
    queries.append(json.dumps(query))

print("__RESULT__:")
print(json.dumps(queries))"}

